<?php declare(strict_types=1);
namespace MOJ\JudicialSystem;
final class Security{public static function boot():void{$c=require __DIR__.'/../config/config.php';if(session_status()!==PHP_SESSION_ACTIVE){session_name($c['security']['session_name']);session_set_cookie_params(['httponly'=>true,'secure'=>!empty($_SERVER['HTTPS']),'samesite'=>'Lax']);session_start();} header("X-Frame-Options: SAMEORIGIN");header("X-Content-Type-Options: nosniff");header("Referrer-Policy: strict-origin-when-cross-origin");header("Content-Security-Policy: default-src 'self' https://cdn.jsdelivr.net https://code.jquery.com; img-src 'self' data:; style-src 'self' 'unsafe-inline' https://cdn.jsdelivr.net; script-src 'self' 'unsafe-inline' https://cdn.jsdelivr.net https://code.jquery.com");} public static function csrf():string{$k=(require __DIR__.'/../config/config.php')['security']['csrf_key'];return $_SESSION[$k]??=$_SESSION[$k]??bin2hex(random_bytes(32));} public static function verifyCsrf(?string $t):void{if(!hash_equals(self::csrf(),(string)$t)){Helper::json(['error'=>'Invalid CSRF token'],419);}} public static function password(string $p):string{return password_hash($p,PASSWORD_ARGON2ID);} public static function requireLogin():void{self::boot();if(empty($_SESSION['user_id'])){header('Location: login.php');exit;}}}
